create table training_jobs
(
    id                   bigint unsigned auto_increment
        primary key,
    created_at           datetime(3)                     null,
    updated_at           datetime(3)                     null,
    deleted_at           datetime(3)                     null,
    display_name         varchar(63)                     not null comment '展示名称',
    user_id              bigint                          not null comment '用户ID',
    namespace            varchar(63) default 'default'   not null comment '命名空间',
    cluster_id           bigint                          not null comment '集群ID',
    framework_type       varchar(50)                     not null comment '框架类型(PYTORCH_DDP/MPI/STANDALONE)',
    image_id             bigint                          not null comment '镜像ID',
    startup_command      text                            null comment '启动命令',
    total_gpu_count      bigint      default 0           null comment 'GPU总数(快照,用于统计)',
    gpu_type             varchar(50)                     null comment 'GPU类型',
    resource_id          bigint                          null comment '资源配置ID',
    worker_count         bigint                          null comment 'Worker数量',
    master_cpu           bigint                          null comment 'Master CPU配置',
    master_memory        bigint                          null comment 'Master内存配置',
    worker_cpu           bigint                          null comment 'Worker CPU配置',
    worker_memory        bigint                          null comment 'Worker内存配置',
    worker_gpu           bigint                          null comment '每个Worker的GPU数量',
    use_shm              tinyint(1)  default 1           null comment '是否使用共享内存',
    shm_size             bigint                          null comment '共享内存大小',
    k8s_job_uid          varchar(128)                    null comment 'K8s Job UID',
    job_name             varchar(128)                    null comment 'K8s Job名称',
    status               varchar(50) default 'SUBMITTED' not null comment '状态',
    error_msg            text                            null comment '错误信息',
    started_at           datetime(3)                     null comment '开始时间',
    finished_at          datetime(3)                     null comment '结束时间',
    enable_tensorboard   tinyint(1)  default 0           null comment '是否启用TensorBoard',
    tensorboard_log_path varchar(512)                    null comment 'TensorBoard日志路径',
    tensorboard_id       bigint                          null comment '关联的TensorBoard ID',
    pay_type             bigint      default 1           null comment '付费类型(1-按量 2-包日 3-包周 4-包月)',
    price                decimal(10, 4)                  null comment '单价',
    order_id             bigint unsigned                 null comment '关联订单ID',
    product_id           bigint unsigned                 null comment '产品ID',
    instance_count       bigint      default 1           null comment '实例数量',
    schedule_strategy    varchar(20) default 'BALANCED'  null comment '调度策略'
);

create index idx_training_jobs_cluster_id
    on training_jobs (cluster_id);

create index idx_training_jobs_deleted_at
    on training_jobs (deleted_at);

create index idx_training_jobs_k8s_job_uid
    on training_jobs (k8s_job_uid);

create index idx_training_jobs_product_id
    on training_jobs (product_id);

create index idx_training_jobs_status
    on training_jobs (status);

create index idx_training_jobs_user_id
    on training_jobs (user_id);

