INSERT INTO aiInfra.training_jobs (id, created_at, updated_at, deleted_at, display_name, user_id, namespace, cluster_id, framework_type, image_id, startup_command, total_gpu_count, gpu_type, resource_id, worker_count, master_cpu, master_memory, worker_cpu, worker_memory, worker_gpu, use_shm, shm_size, k8s_job_uid, job_name, status, error_msg, started_at, finished_at, enable_tensorboard, tensorboard_log_path, tensorboard_id, pay_type, price, order_id, product_id, instance_count, schedule_strategy) VALUES (30, '2026-01-05 21:49:26.075', '2026-01-29 00:25:53.853', '2026-01-29 00:25:53.859', '3', 1, 'hmz', 1, 'MPI', 5, 'mpirun -np 2 -H ${MPI_HOSTS} python -c "
import tensorflow as tf
import socket
import os

hostname = socket.gethostname()
rank = int(os.environ.get(\'OMPI_COMM_WORLD_RANK\', 0))

print(f\'[{hostname}] Rank {rank} - Starting training...\')

# 创建简单模型
model = tf.keras.Sequential([
    tf.keras.layers.Dense(128, activation=\'relu\', input_shape=(784,)),
    tf.keras.layers.Dense(10, activation=\'softmax\')
])
model.compile(optimizer=\'adam\', loss=\'sparse_categorical_crossentropy\', metrics=[\'accuracy\'])

# 生成随机数据模拟训练
import numpy as np
x_train = np.random.random((1000, 784))
y_train = np.random.randint(0, 10, (1000,))

# 训练 3 个 epoch
model.fit(x_train, y_train, epochs=3, batch_size=32, verbose=1)

print(f\'[{hostname}] Rank {rank} - Training completed!\')
"', 0, '', 3, 2, 1, 1, 1, 1, 0, 1, 2, '9f2a47c1-3c34-4e47-bbdb-35d4f8278405', 'training-f5ce5b', 'KILLED', '', '2026-01-05 21:49:29.249', '2026-01-05 21:50:52.842', 0, 'logs', 0, 1, 1.0000, null, null, 1, 'BALANCED');
